    public DataSeederService(
        IServiceScopeFactory scopeFactory,
        IConfiguration configuration,
        ILogger<DataSeederService> logger)
    {
        _scopeFactory = scopeFactory;
        _configuration = configuration;
        _logger = logger;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        var privateKey = _configuration["Explorer:DevAccountPrivateKey"];
        var rpcUrl = _configuration["Explorer:RpcUrl"];

        if (string.IsNullOrEmpty(privateKey) || string.IsNullOrEmpty(rpcUrl))
        {
            _logger.LogWarning("DataSeeder: No DevAccountPrivateKey or RpcUrl configured, skipping seed");
            return;
        }

        await Task.Delay(3000, stoppingToken);

        var account = new Account(privateKey);
        var web3 = new Nethereum.Web3.Web3(account, rpcUrl);
        _logger.LogInformation("DataSeeder: Deploying contracts from {Address}", account.Address);

        string? erc20Address = null;
        string? emitterAddress = null;
        string? complexStructAddress = null;
        string? multiCallAddress = null;

        try
        {
            erc20Address = await DeployErc20Async(web3, account.Address, stoppingToken);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "DataSeeder: Failed to deploy ERC20");
        }

        try
        {
            emitterAddress = await DeployEventEmitterAsync(web3, account.Address, stoppingToken);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "DataSeeder: Failed to deploy EventEmitter");
        }

        try
        {
            complexStructAddress = await DeployComplexStructAsync(web3, account.Address, stoppingToken);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "DataSeeder: Failed to deploy ComplexStructRegistry");
        }

        try
        {
            multiCallAddress = await DeployMultiCallTestAsync(web3, account.Address, stoppingToken);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "DataSeeder: Failed to deploy MultiCallTest");
        }

        await WaitForDbReadyAsync(stoppingToken);

        using var scope = _scopeFactory.CreateScope();
        var abiStorage = scope.ServiceProvider.GetRequiredService<IAbiStorageService>();

        if (erc20Address != null)
        {
            try
            {
                await abiStorage.StoreAbiAsync(erc20Address, FULL_ERC20_ABI, "Mock Token (MOCK)");
                _logger.LogInformation("DataSeeder: Stored ERC20 ABI for {Address}", erc20Address);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "DataSeeder: FAILED to store ERC20 ABI for {Address}", erc20Address);
            }
        }

        if (emitterAddress != null)
        {
            try
            {
                await abiStorage.StoreAbiAsync(emitterAddress, EVENT_EMITTER_ABI, "EventEmitter");
                _logger.LogInformation("DataSeeder: Stored EventEmitter ABI for {Address}", emitterAddress);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "DataSeeder: FAILED to store EventEmitter ABI for {Address}", emitterAddress);
            }
        }

        if (complexStructAddress != null)
        {
            try
            {
                await abiStorage.StoreAbiAsync(complexStructAddress, COMPLEX_STRUCT_ABI, "ComplexStructRegistry");
                _logger.LogInformation("DataSeeder: Stored ComplexStructRegistry ABI for {Address}", complexStructAddress);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "DataSeeder: FAILED to store ComplexStructRegistry ABI for {Address}", complexStructAddress);
            }
        }

        if (multiCallAddress != null)
        {
            try
            {
                await abiStorage.StoreAbiAsync(multiCallAddress, MULTICALL_TEST_ABI, "MultiCallTest");
                _logger.LogInformation("DataSeeder: Stored MultiCallTest ABI for {Address}", multiCallAddress);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "DataSeeder: FAILED to store MultiCallTest ABI for {Address}", multiCallAddress);
            }
        }

        _logger.LogInformation("=== DATA SEEDER COMPLETE ===");
        _logger.LogInformation("ERC20 (Mock Token):    /contract/{Address}", erc20Address ?? "FAILED");
        _logger.LogInformation("EventEmitter:          /contract/{Address}", emitterAddress ?? "FAILED");
        _logger.LogInformation("ComplexStructRegistry: /contract/{Address}", complexStructAddress ?? "FAILED");
        _logger.LogInformation("MultiCallTest:         /contract/{Address}", multiCallAddress ?? "FAILED");
        _logger.LogInformation("Dev Account:           {Address}", account.Address);
        _logger.LogInformation("============================");
    }

    private async Task<string> DeployErc20Async(Nethereum.Web3.Web3 web3, string from, CancellationToken ct)
    {
        _logger.LogInformation("DataSeeder: Deploying ERC20 contract...");
        var gas = await web3.Eth.DeployContract.EstimateGasAsync(
            FULL_ERC20_ABI, ERC20_BYTECODE, from);
        var receipt = await web3.Eth.DeployContract.SendRequestAndWaitForReceiptAsync(
            FULL_ERC20_ABI, ERC20_BYTECODE, from, gas);

        var contractAddress = receipt.ContractAddress;
        _logger.LogInformation("DataSeeder: ERC20 deployed at {Address}", contractAddress);

        _logger.LogInformation("DataSeeder: Minting 10,000 MOCK tokens...");
        var mintHandler = web3.Eth.GetContractTransactionHandler<MintFunction>();
        await mintHandler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new MintFunction { To = from, Amount = BigInteger.Parse("10000000000000000000000") });

        var recipient = "0x70997970C51812dc3A010C7d01b50e0d17dc79C8";
        _logger.LogInformation("DataSeeder: Transferring 1,000 MOCK to {Recipient}...", recipient);
        var transferHandler = web3.Eth.GetContractTransactionHandler<TransferFunction>();
        await transferHandler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new TransferFunction { To = recipient, Value = BigInteger.Parse("1000000000000000000000") });

        return contractAddress;
    }

    private async Task<string> DeployEventEmitterAsync(Nethereum.Web3.Web3 web3, string from, CancellationToken ct)
    {
        _logger.LogInformation("DataSeeder: Deploying EventEmitter contract...");
        var gas = await web3.Eth.DeployContract.EstimateGasAsync(
            EVENT_EMITTER_ABI, EVENT_EMITTER_BYTECODE, from);
        var receipt = await web3.Eth.DeployContract.SendRequestAndWaitForReceiptAsync(
            EVENT_EMITTER_ABI, EVENT_EMITTER_BYTECODE, from, gas);

        var contractAddress = receipt.ContractAddress;
        _logger.LogInformation("DataSeeder: EventEmitter deployed at {Address}", contractAddress);

        _logger.LogInformation("DataSeeder: Calling emitEvent() 3 times...");
        var contract = web3.Eth.GetContract(EVENT_EMITTER_ABI, contractAddress);
        var emitFunction = contract.GetFunction("emitEvent");
        for (int i = 0; i < 3; i++)
        {
            var emitGas = await emitFunction.EstimateGasAsync(from, null, null);
            await emitFunction.SendTransactionAndWaitForReceiptAsync(from, emitGas, null, ct);
        }

        return contractAddress;
    }

    private async Task WaitForDbReadyAsync(CancellationToken ct)
    {
        using var scope = _scopeFactory.CreateScope();
        var abiStorage = scope.ServiceProvider.GetService<IAbiStorageService>();
        if (abiStorage == null) return;

        for (int i = 0; i < 30; i++)
        {
            ct.ThrowIfCancellationRequested();
            try
            {
                await abiStorage.GetContractAbiAsync("0x0000000000000000000000000000000000000000");
                return;
            }
            catch
            {
                _logger.LogDebug("DataSeeder: Waiting for DB schema... attempt {Attempt}", i + 1);
                await Task.Delay(2000, ct);
            }
        }

        _logger.LogWarning("DataSeeder: DB not ready after 60s, attempting to store ABIs anyway");
    }

    [Function("mint")]
    private class MintFunction : FunctionMessage
    {
        [Parameter("address", "to", 1)]
        public virtual string To { get; set; } = "";
        [Parameter("uint256", "amount", 2)]
        public virtual BigInteger Amount { get; set; }
    }

    [Function("transfer", "bool")]
    private class TransferFunction : FunctionMessage
    {
        [Parameter("address", "to", 1)]
        public virtual string To { get; set; } = "";
        [Parameter("uint256", "value", 2)]
        public virtual BigInteger Value { get; set; }
    }

    private async Task<string> DeployComplexStructAsync(Nethereum.Web3.Web3 web3, string from, CancellationToken ct)
    {
        _logger.LogInformation("DataSeeder: Deploying ComplexStructRegistry contract...");
        var gas = await web3.Eth.DeployContract.EstimateGasAsync(
            COMPLEX_STRUCT_ABI, COMPLEX_STRUCT_BYTECODE, from);
        var receipt = await web3.Eth.DeployContract.SendRequestAndWaitForReceiptAsync(
            COMPLEX_STRUCT_ABI, COMPLEX_STRUCT_BYTECODE, from, gas);

        var contractAddress = receipt.ContractAddress;
        _logger.LogInformation("DataSeeder: ComplexStructRegistry deployed at {Address}", contractAddress);

        _logger.LogInformation("DataSeeder: Adding sample employee...");
        var addHandler = web3.Eth.GetContractTransactionHandler<AddEmployeeFunction>();
        await addHandler.SendRequestAndWaitForReceiptAsync(contractAddress, new AddEmployeeFunction
        {
            Employee = new EmployeeDTO
            {
                Person = new PersonDTO
                {
                    Name = "Alice Johnson",
                    Age = 30,
                    Addr = new AddressDTO
                    {
                        Street = "123 Blockchain Ave",
                        City = "Cryptoville",
                        PostCode = "CR1 0PT",
                        Country = "Decentraland"
                    }
                },
                EmployeeId = 0,
                Department = "Engineering",
                Salary = 85000
            }
        });

        return contractAddress;
    }

    [FunctionOutput]
    private class AddressDTO
    {
        [Parameter("string", "street", 1)]
        public virtual string Street { get; set; } = "";
        [Parameter("string", "city", 2)]
        public virtual string City { get; set; } = "";
        [Parameter("string", "postCode", 3)]
        public virtual string PostCode { get; set; } = "";
        [Parameter("string", "country", 4)]
        public virtual string Country { get; set; } = "";
    }

    [FunctionOutput]
    private class PersonDTO
    {
        [Parameter("string", "name", 1)]
        public virtual string Name { get; set; } = "";
        [Parameter("uint256", "age", 2)]
        public virtual BigInteger Age { get; set; }
        [Parameter("tuple", "addr", 3)]
        public virtual AddressDTO Addr { get; set; } = new();
    }

    [FunctionOutput]
    private class EmployeeDTO
    {
        [Parameter("tuple", "person", 1)]
        public virtual PersonDTO Person { get; set; } = new();
        [Parameter("uint256", "employeeId", 2)]
        public virtual BigInteger EmployeeId { get; set; }
        [Parameter("string", "department", 3)]
        public virtual string Department { get; set; } = "";
        [Parameter("uint256", "salary", 4)]
        public virtual BigInteger Salary { get; set; }
    }

    [Function("addEmployee", "uint256")]
    private class AddEmployeeFunction : FunctionMessage
    {
        [Parameter("tuple", "employee", 1)]
        public virtual EmployeeDTO Employee { get; set; } = new();
    }

    private async Task<string> DeployMultiCallTestAsync(Nethereum.Web3.Web3 web3, string from, CancellationToken ct)
    {
        _logger.LogInformation("DataSeeder: Deploying MultiCallTest contract...");
        var gas = await web3.Eth.DeployContract.EstimateGasAsync(
            MULTICALL_TEST_ABI, MULTICALL_TEST_BYTECODE, from);
        var receipt = await web3.Eth.DeployContract.SendRequestAndWaitForReceiptAsync(
            MULTICALL_TEST_ABI, MULTICALL_TEST_BYTECODE, from, gas);

        var contractAddress = receipt.ContractAddress;
        _logger.LogInformation("DataSeeder: MultiCallTest deployed at {Address}", contractAddress);

        // 1. deposit() with 1 ETH — exercises payable + Deposit event + state change
        _logger.LogInformation("DataSeeder: MultiCallTest deposit(1 ETH)...");
        var depositHandler = web3.Eth.GetContractTransactionHandler<MCDepositFunction>();
        await depositHandler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new MCDepositFunction { AmountToSend = BigInteger.Parse("1000000000000000000") });

        // 2. createChild() — exercises CREATE internal tx + ChildCreated event
        _logger.LogInformation("DataSeeder: MultiCallTest createChild()...");
        var createChildHandler = web3.Eth.GetContractTransactionHandler<MCCreateChildFunction>();
        await createChildHandler.SendRequestAndWaitForReceiptAsync(contractAddress, new MCCreateChildFunction());

        // 3. pingChild() — exercises multi-hop CALL chain (parent→child→parent callback)
        _logger.LogInformation("DataSeeder: MultiCallTest pingChild()...");
        var pingHandler = web3.Eth.GetContractTransactionHandler<MCPingChildFunction>();
        await pingHandler.SendRequestAndWaitForReceiptAsync(contractAddress, new MCPingChildFunction());

        // 4. forwardDeposit(self) with 0.5 ETH — exercises internal CALL with value transfer
        _logger.LogInformation("DataSeeder: MultiCallTest forwardDeposit(self, 0.5 ETH)...");
        var forwardHandler = web3.Eth.GetContractTransactionHandler<MCForwardDepositFunction>();
        await forwardHandler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new MCForwardDepositFunction
            {
                Target = contractAddress,
                AmountToSend = BigInteger.Parse("500000000000000000")
            });

        // 5. withdraw(999 ETH) — exercises revert with custom error InsufficientBalance
        _logger.LogInformation("DataSeeder: MultiCallTest withdraw(999 ETH) — expect revert...");
        try
        {
            var withdrawHandler = web3.Eth.GetContractTransactionHandler<MCWithdrawFunction>();
            await withdrawHandler.SendRequestAndWaitForReceiptAsync(contractAddress,
                new MCWithdrawFunction { Amount = BigInteger.Parse("999000000000000000000") });
        }
        catch (Exception ex)
        {
            _logger.LogInformation("DataSeeder: MultiCallTest withdraw reverted as expected: {Message}", ex.Message);
        }

        // 6. Second pingChild() — more trace data
        _logger.LogInformation("DataSeeder: MultiCallTest pingChild() again...");
        await pingHandler.SendRequestAndWaitForReceiptAsync(contractAddress, new MCPingChildFunction());

        return contractAddress;
    }

    [Function("deposit")]
    private class MCDepositFunction : FunctionMessage { }

    [Function("withdraw")]
    private class MCWithdrawFunction : FunctionMessage
    {
        [Parameter("uint256", "amount", 1)]
        public virtual BigInteger Amount { get; set; }
    }

    [Function("createChild")]
    private class MCCreateChildFunction : FunctionMessage { }

    [Function("pingChild", "uint256")]
    private class MCPingChildFunction : FunctionMessage { }

    [Function("forwardDeposit")]
    private class MCForwardDepositFunction : FunctionMessage
    {
        [Parameter("address", "target", 1)]
        public virtual string Target { get; set; } = "";
    }
